if(!s.includes('bare-customer-orders-v2')){
 const n="if(url.pathname.startsWith('/api/admin/'))return adminApi(request,env,url);";
 if(!s.includes(n))throw new Error('router insertion point not found');
 s=s.replace(n,"if(url.pathname==='/api/customer/orders')return customerOrdersApi(request,env);"+n);
 s+=String.raw`
/* bare-customer-orders-v2 */
async function customerOrdersApi(request,env){if(request.method!=='GET')return jsonResponse({message:'Method not allowed'},405);try{const h=request.headers.get('authorization')||'',token=h.replace(/^Bearer\s+/i,'').trim();if(!token)throw new Error('로그인이 필요합니다.');const ur=await fetch(supabaseUrl(env)+'/auth/v1/user',{headers:{apikey:supabasePublicKey(env),Authorization:'Bearer '+token}}),user=await ur.json().catch(()=>null);if(!ur.ok||!user?.email)throw new Error('로그인 세션을 확인할 수 없습니다.');const rows=await supabaseRest(env,'orders?select=order_id,created_at,amount,fulfillment_status,tracking_company,tracking_number&email=ilike.'+encodeURIComponent(String(user.email).trim().toLowerCase())+'&order=created_at.desc&limit=100'),ids=rows.map(o=>o.order_id).filter(Boolean);let items=[];if(ids.length)items=await supabaseRest(env,'order_items?select=order_id,product_title,option_text,price,quantity,image_url&order_id=in.('+ids.map(id=>encodeURIComponent('"'+id+'"')).join(',')+')&limit=500');const grouped=items.reduce((m,i)=>{(m[i.order_id]||=[]).push(i);return m},{});return jsonResponse({orders:rows.map(o=>({...o,items:grouped[o.order_id]||[]}))})}catch(e){return jsonResponse({message:e.message||'주문 배송정보를 불러오지 못했습니다.'},401)}}
const bareMyPageShippingV2=myPage;
myPage=function(){const h=bareMyPageShippingV2(),css='<style id="customer-tracking-style">.tracking-info{display:flex;gap:8px;align-items:center;flex-wrap:wrap;margin-top:8px;font:800 11px/1.4 Pretendard,sans-serif}.tracking-number{border:0;border-bottom:1px solid #111;background:none;padding:0 0 2px;font-weight:900;cursor:pointer}</style>',js=\`<script type="module" id="customer-tracking-script">import{createClient}from'https://cdn.jsdelivr.net/npm/@supabase/supabase-js/+esm';const sb=createClient('https://adltmckypuqwzbcuvuuh.supabase.co','sb_publishable_ZDEvoNTASICy-Z2hqqTOGA_EHFz2Yv1'),{data}=await sb.auth.getSession(),session=data?.session;if(session){try{const r=await fetch('/api/customer/orders',{headers:{Authorization:'Bearer '+session.access_token},cache:'no-store'}),d=await r.json();if(!r.ok)throw new Error(d.message);const labels={paid:'결제완료',confirmed:'발주확인',ready:'상품준비중',shipping:'배송중',done:'배송완료',cancel_requested:'취소요청',cancelled:'취소완료',exchange_requested:'교환요청',return_requested:'반품요청'},esc=v=>String(v??'').replace(/[&<>"']/g,c=>'&#'+c.charCodeAt(0)+';'),money=v=>'₩'+Number(v||0).toLocaleString('ko-KR'),orders=(d.orders||[]).filter(o=>new Date(o.created_at).getTime()>=Date.now()-90*86400000),status=o=>labels[o.fulfillment_status]||o.fulfillment_status||'-',list=document.getElementById('my-order-list');document.getElementById('order-total').textContent=money(orders.reduce((a,o)=>a+Number(o.amount||0),0));document.getElementById('count-pending').textContent=orders.filter(o=>o.fulfillment_status==='paid').length;document.getElementById('count-ready').textContent=orders.filter(o=>['confirmed','ready'].includes(o.fulfillment_status)).length;document.getElementById('count-shipping').textContent=orders.filter(o=>o.fulfillment_status==='shipping').length;document.getElementById('count-complete').textContent=orders.filter(o=>o.fulfillment_status==='done').length;document.getElementById('count-cancel').textContent=orders.filter(o=>/cancel/.test(o.fulfillment_status||'')).length;list.innerHTML=orders.length?orders.map(o=>{const i=(o.items||[])[0]||{},more=Math.max(0,(o.items||[]).length-1),track=o.tracking_number?'<div class="tracking-info"><strong>배송정보</strong><span>'+esc(o.tracking_company||'택배사')+'</span><button class="tracking-number" data-copy-tracking="'+esc(o.tracking_number)+'">'+esc(o.tracking_number)+'</button></div>':'';return '<article class="order-row"><img src="'+esc(i.image_url||'')+'" alt=""><div><div class="order-title">'+esc(i.product_title||'BARE. product')+(more?' 외 '+more+'건':'')+'</div><div class="order-meta">'+esc(i.option_text||'')+'</div><div class="order-meta">'+esc(o.order_id||'')+'</div>'+track+'</div><strong class="order-price">'+money(o.amount)+'</strong><span class="order-status">'+esc(status(o))+'</span></article>'}).join(''):'<p class="empty-orders">최근 주문 내역이 없습니다.</p>';list.onclick=async e=>{const b=e.target.closest('[data-copy-tracking]');if(!b)return;await navigator.clipboard.writeText(b.dataset.copyTracking);const t=b.textContent;b.textContent='복사됨';setTimeout(()=>b.textContent=t,1000)}}catch(e){console.warn('customer orders',e)}}</script>\`;return h.replace('</head>',css+'</head>').replace('</body>',js+'</body>')};
`;
 fs.writeFileSync('_worker.js',s);
}
